import type { EditorView } from '@codemirror/view';
import type { Tree } from '@lezer/common';

import { sortFilterFieldTree } from './tree-precedence.js';
import { usedErrors } from '../../editor-state-configs/editor-config.js';
import type { FilterFieldProps } from '../../FilterField.types.js';
import type { NumberFormatParser } from '../../parser/getNumberParser.js';
import type { FilterFieldFlatGroupNode } from '../../types/conversion-utils.js';
import type { FilterFieldError } from '../../types/filter-field-error.js';
import type {
  FilterFieldLezerNodeType,
  FilterFieldRootNode,
  FilterFieldTree,
} from '../../types/tree-nodes.js';
import type { FilterFieldCustomTypes } from '../../types/validation.js';
import { convertFilterGroup } from './lezer-tree-conversion/parent-node/group.js';
import type { InternalValidatorMap } from '../../utils/validation-utils/normalize-validator-map.js';

/**
 * Used parser version
 * @internal
 */
export const parserVersion = '004';

/**
 * Iterate over the parsed document and convert the lezer tree to an object.
 * @internal
 */
export function convertLezerTree({
  tree,
  view,
  numberParser,
  doc,
  internalValidatorMap,
  customTypes,
  parserConfig,
}: {
  tree: Tree;
  numberParser: NumberFormatParser;
  view?: EditorView;
  doc?: string;
  internalValidatorMap?: InternalValidatorMap;
  customTypes?: FilterFieldCustomTypes;
  parserConfig?: FilterFieldProps['parserConfig'];
}): { tree?: FilterFieldTree; isValid: boolean; isValidSearch: boolean } {
  const errorsStateField = view?.state.field(usedErrors, false);

  if (!doc || doc === '') {
    errorsStateField && (errorsStateField.errors = []);
    return { isValid: true, isValidSearch: true };
  }

  const { tree: convertedFlatTree, errors: initialConversionErrors } =
    convertFlatLezerTree({
      tree,
      numberParser,
      doc,
      internalValidatorMap,
      customTypes,
      parserConfig,
    });

  const {
    tree: convertedTree,
    errors: sortedTreeErrors,
    isValidSearch,
  } = sortFilterFieldTree(convertedFlatTree, parserConfig, doc);

  const errors = [...initialConversionErrors, ...sortedTreeErrors];

  if (errorsStateField) {
    errors.sort((a, b) => (a.range.from < b.range.from ? -1 : 1));
    errorsStateField.errors = errors;
  }

  if (convertedTree) {
    (convertedTree as FilterFieldRootNode).version = '007';
  }

  return {
    tree: convertedTree as FilterFieldTree,
    isValid: errors.length === 0,
    isValidSearch: isValidSearch ?? sortedTreeErrors,
  };
}

/**
 * Iterate over the parsed document and convert the lezer tree to filter field nodes.
 * @internal
 */
function convertFlatLezerTree({
  tree,
  numberParser,
  doc,
  internalValidatorMap,
  customTypes,
  parserConfig,
}: Parameters<typeof convertLezerTree>[0]): {
  tree?: FilterFieldFlatGroupNode | undefined;
  errors: FilterFieldError[];
} {
  if (!doc || doc.toString() === '') {
    return { errors: [] };
  }

  let convertedTree: FilterFieldFlatGroupNode = {
    type: 'Group',
    children: [],
    range: { from: 0, to: tree.topNode.to },
    logicalOperator: 'AND',
    explicitLogicalOperator: false,
    explicit: false,
  };

  const errors: FilterFieldError[] = [];

  /**
   * ATTENTION:
   * When returning 'false' from the 'enter' callback, children of the respective node
   * will not be iterated over. Also, the 'leave' callback will not be executed for the
   * respective node. Hence, all cleanup (e.g. reducing the 'nestingLevel' again) must
   * be performed when handling the node in the 'enter' callback.
   */
  tree.iterate({
    from: tree.topNode.from,
    to: tree.topNode.to,
    enter: (_node) => {
      const node = _node.node;

      if ((node.name as FilterFieldLezerNodeType) === 'Filter') {
        const { convertedNode, errors: groupErrors } = convertFilterGroup(
          node,
          doc,
          numberParser,
          internalValidatorMap,
          customTypes,
          parserConfig,
          'Filter',
        );
        convertedTree = convertedNode;
        errors.push(...groupErrors);

        return false;
      } else {
        // eslint-disable-next-line no-console
        console.log(
          `${doc.toString()} | Syntax node '${
            node.name
          }' cannot be converted. Please make sure to handle all nodes accordingly.`,
        );
      }
    },
  });

  const filter = {
    tree: convertedTree,
    errors,
  };

  return filter;
}
